import 'package:cloud_firestore/cloud_firestore.dart'; import 'package:flutter/material.dart'; import '../services/firestore_service.dart';
class ResourcesScreen extends StatefulWidget { const ResourcesScreen({super.key}); @override State<ResourcesScreen> createState()=>_ResourcesScreenState(); }
class _ResourcesScreenState extends State<ResourcesScreen>{ final searchController=TextEditingController(); String keyword=''; @override void dispose(){searchController.dispose(); super.dispose();} bool match(Map<String,dynamic> data){ if(keyword.isEmpty) return true; final k=keyword.toLowerCase(); return (data['title']??'').toString().toLowerCase().contains(k)||(data['category']??'').toString().toLowerCase().contains(k)||(data['courseCode']??'').toString().toLowerCase().contains(k); }
@override Widget build(BuildContext context){ final service=FirestoreService(); return Scaffold(appBar: AppBar(title: const Text('Resource Locator')), body: Column(children:[ Padding(padding: const EdgeInsets.all(16), child: TextField(controller: searchController, decoration: const InputDecoration(labelText:'Search by title, category or course code', border: OutlineInputBorder(), prefixIcon: Icon(Icons.search)), onChanged:(v)=>setState(()=>keyword=v))), Expanded(child: StreamBuilder<QuerySnapshot<Map<String,dynamic>>>(stream: service.streamCollection('resources', orderBy:'createdAt', descending:true), builder:(context,snapshot){ if(snapshot.hasError) return Center(child: Text('Error: ${snapshot.error}')); if(!snapshot.hasData) return const Center(child:CircularProgressIndicator()); final docs=snapshot.data!.docs.where((d)=>match(d.data())).toList(); if(docs.isEmpty) return const Center(child: Text('No resources found.')); return ListView.builder(padding: const EdgeInsets.all(16), itemCount: docs.length, itemBuilder:(context,index){ final data=docs[index].data(); final link=(data['linkUrl']??data['fileUrl']??'').toString(); return Card(child: ListTile(leading: const Icon(Icons.folder,color:Colors.orange), title: Text(data['title']??'Untitled'), subtitle: Text('${data['category']??'-'} ${data['courseCode']??''}\n$link'), isThreeLine:true)); }); })), ])); }}
